begin
  for m in (
    select * from (values
      ('Nhận nuôi thú cưng', 'adopting a pet at the shelter', '🐶',
        array['sticker-103', 'sticker-104', 'sticker-105'],
        'Hello!', 'Trẻ chào nhân viên trạm cứu hộ thú cưng.',
        'Can I adopt a kitten, please?', 'Trẻ hỏi xin nhận nuôi một bé mèo con (kitten / puppy).',
        'The black and white one, please.', 'Trẻ chọn màu sắc của thú cưng (black and white / yellow / grey).',
        'I will feed her every day.', 'Trẻ hứa sẽ chăm sóc thú cưng chu đáo (feed her every day / play with her).',
        'Thank you! Goodbye!', 'Trẻ cảm ơn nhân viên và chào tạm biệt.'),
      ('Làm món sa-lát trái cây', 'making a fruit salad', '🥗',
        array['sticker-106', 'sticker-107', 'sticker-108'],
        'Good morning!', 'Trẻ chào bạn cùng làm bếp.',
        'Let''s wash the strawberries first.', 'Trẻ đề nghị rửa loại trái cây đầu tiên (strawberries / grapes / apples).',
        'Can you cut the bananas, please?', 'Trẻ nhờ bạn cắt loại trái cây thứ hai (bananas / mangoes).',
        'Let''s mix them in the big bowl.', 'Trẻ rủ bạn trộn tất cả trái cây vào bát lớn.',
        'It looks delicious! Thank you!', 'Trẻ khen món ăn ngon mắt và cảm ơn bạn.'),
      ('Kể về siêu anh hùng', 'describing a superhero', '🦸',
        array['sticker-109', 'sticker-110', 'sticker-111'],
        'Look at this!', 'Trẻ chỉ cho bạn xem hình/tượng siêu anh hùng.',
        'My favorite superhero is Spiderman.', 'Trẻ giới thiệu siêu anh hùng yêu thích của mình (Spiderman / Batman / Iron Man).',
        'He wears a red and blue suit.', 'Trẻ mô tả màu sắc bộ trang phục (red and blue / black / gold).',
        'He can climb tall buildings.', 'Trẻ kể về siêu năng lực đặc biệt (climb buildings / fly / run fast).',
        'He is very cool!', 'Trẻ khen ngợi siêu anh hùng thật ngầu để kết thúc.'),
      ('Dọn dẹp phòng ngủ', 'cleaning my bedroom', '🧹',
        array['sticker-112', 'sticker-113', 'sticker-114'],
        'Let''s clean my bedroom!', 'Trẻ rủ nhân vật đồng hành/bạn dọn dẹp phòng ngủ.',
        'I will put the toys in the box.', 'Trẻ dọn dẹp đồ chơi và cất chúng vào hộp.',
        'Can you help me make the bed, please?', 'Trẻ nhờ giúp dọn dẹp giường ngủ ngăn nắp.',
        'I will wipe the desk.', 'Trẻ lau dọn bàn học gọn gàng.',
        'Wow, my room looks so clean!', 'Trẻ tự hào ngắm nhìn căn phòng sạch sẽ và hoàn thành.'),
      ('Chuẩn bị đi học ngày mưa', 'preparing for a rainy school day', '🌧️',
        array['sticker-115', 'sticker-116', 'sticker-117'],
        'Look outside, it is raining!', 'Trẻ chỉ ra ngoài cửa sổ báo trời đang mưa.',
        'I need to wear my yellow raincoat.', 'Trẻ nói cần mặc áo mưa (yellow / red / blue raincoat).',
        'Can you hand me my boots, please?', 'Trẻ nhờ lấy đôi ủng đi mưa.',
        'I will carry my umbrella too.', 'Trẻ nói sẽ mang theo chiếc ô để che chắn.',
        'I am ready for school. Let''s go!', 'Trẻ sẵn sàng đi học và rủ bố mẹ khởi hành.'),
      ('Chơi xích đu ở sân chơi', 'playing on the swings', '🎠',
        array['sticker-118', 'sticker-119', 'sticker-120'],
        'Hi, can I play on the swings?', 'Trẻ chào bạn ở sân chơi và xin phép chơi xích đu.',
        'Can you push me, please?', 'Trẻ nhờ bạn đẩy hộ xích đu.',
        'Higher, please!', 'Trẻ thích thú muốn đẩy cao hơn chút nữa.',
        'It is so fun!', 'Trẻ bày tỏ niềm vui khi đang bay lượn trên xích đu.',
        'Thank you! It is your turn now.', 'Trẻ cảm ơn bạn và nhường lượt chơi tiếp theo.'),
      ('Xin phép xem TV', 'asking permission to watch TV', '📺',
        array['sticker-121', 'sticker-122', 'sticker-123'],
        'Mom, can I watch TV, please?', 'Trẻ xin phép mẹ/bố xem TV.',
        'I finished all my homework.', 'Trẻ trình bày lý do đã làm xong bài tập về nhà.',
        'I want to watch cartoons.', 'Trẻ nói chương trình muốn xem (cartoons / animal shows).',
        'Just for thirty minutes, please.', 'Trẻ thương lượng thời gian xem (thirty minutes / one hour).',
        'Thank you, Mom! You are the best!', 'Trẻ cảm ơn mẹ vui vẻ.'),
      ('Đi bơi ở hồ bơi', 'going swimming at the pool', '🏊',
