        'Let''s slide down on my sled.', 'Trẻ rủ rê chơi trượt từ trên đồi xuống bằng ván trượt.',
        'Can you push me, Dad?', 'Trẻ nhờ bố đẩy một lực từ phía sau để lấy đà.',
        'Wheee! This is so fast!', 'Trẻ hét lên phấn khích khi ván trượt lao đi với tốc độ cao.',
        'I am covered in snow! Let''s do it again.', 'Trẻ thông báo mình dính đầy tuyết nhưng vẫn vui vẻ rủ chơi thêm lần nữa.'),
      ('Bỏ ống heo tiết kiệm', 'saving money in a piggy bank', '🐷',
        array['sticker-298', 'sticker-299', 'sticker-300'],
        'Mom, I have some extra coins.', 'Trẻ thông báo với mẹ rằng mình đang có vài đồng tiền lẻ dư.',
        'I will put them in my pink piggy bank.', 'Trẻ chủ động nói sẽ cất tiền vào con heo đất màu hồng.',
        'Listen to the sound it makes! Clink clink!', 'Trẻ bảo mẹ lắng nghe tiếng đồng xu rơi vào trong heo đất.',
        'I am saving money to buy a new bicycle.', 'Trẻ giải thích mục tiêu tiết kiệm là để mua một chiếc xe đạp mới.',
        'I will feed my piggy bank every day.', 'Trẻ hứa sẽ "cho heo ăn" tiền tiết kiệm mỗi ngày.')
    ) as t(title, topic, icon, pool, s1, i1, s2, i2, s3, i3, s4, i4, s5, i5)
  )
  loop
    if not exists (select 1 from missions where title = m.title) then
      insert into missions (id, language_id, title, topic, level, step_count, sticker_pool, icon)
      values (gen_random_uuid(), 'en', m.title, m.topic, 'beginner', 5, m.pool, m.icon)
      returning id into v_mission_id;

      insert into mission_steps (mission_id, step_order, target_sentence, intent) values
        (v_mission_id, 1, m.s1, m.i1),
        (v_mission_id, 2, m.s2, m.i2),
        (v_mission_id, 3, m.s3, m.i3),
        (v_mission_id, 4, m.s4, m.i4),
        (v_mission_id, 5, m.s5, m.i5);
    else
      -- Update sticker_pool for existing missions
      update missions
      set sticker_pool = m.pool
      where title = m.title;
    end if;
  end loop;
end $$;
